interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Helper to map weather conditions to Lucide icons or emojis
function WeatherIcon(props: { condition: string; size?: number; color?: string }) {
  const iconName = useMemo(() => {
    const c = (props.condition || '').toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return 'sun';
    if (c.includes('cloud') && (c.includes('sun') || c.includes('partly'))) return 'cloud-sun';
    if (c.includes('cloud')) return 'cloud';
    if (c.includes('rain') || c.includes('drizzle') || c.includes('shower')) return 'cloud-rain';
    if (c.includes('snow') || c.includes('ice') || c.includes('freeze')) return 'snowflake';
    if (c.includes('thunder') || c.includes('storm') || c.includes('lightning')) return 'cloud-lightning';
    if (c.includes('wind') || c.includes('breeze')) return 'wind';
    if (c.includes('mist') || c.includes('fog') || c.includes('haze')) return 'framer'; // Closest generic representation
    return 'cloud';
  }, [props.condition]);

  return <Icon name={iconName} size={props.size ?? 24} color={props.color ?? 'currentColor'} />;
}

export default function Component(props: Props) {
  // Access session information if needed (mock for demonstration)
  // Current weather display for the city provided in props

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Card shadow="md" radius="xl" padding="var(--ggui-spacing-8)">
        <Stack gap="var(--ggui-spacing-6)">
          {/* Header Section */}
          <Row justify="between" align="start">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                {props.city}
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                {new Date().toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' })}
              </Text>
            </Stack>
            <Badge variant="success" size="sm">
              Live
            </Badge>
          </Row>

          {/* Current Weather Display */}
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-2)">
              <Row gap="var(--ggui-spacing-4)" align="center">
                <WeatherIcon condition={props.condition} size={64} color="var(--ggui-color-primary-600)" />
                <Stack gap="0">
                  <Heading level={1} color="var(--ggui-color-onSurface)" style={{ fontSize: 'var(--ggui-font-size-4xl)' }}>
                    {props.temperature}°{props.unit}
                  </Heading>
                  <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurfaceVariant)">
                    {props.condition}
                  </Text>
                </Stack>
              </Row>
            </Stack>

            <Stack gap="var(--ggui-spacing-3)" align="end">
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Icon name="droplets" size={18} color="var(--ggui-color-primary-400)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Humidity: <Text is="span" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                </Text>
              </Row>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Icon name="wind" size={18} color="var(--ggui-color-primary-400)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Wind: <Text is="span" color="var(--ggui-color-onSurface)">{props.windSpeed} km/h</Text>
                </Text>
              </Row>
            </Stack>
          </Row>

          <Divider margin="var(--ggui-spacing-4)" />

          {/* 5-Day Forecast Strip */}
          <Stack gap="var(--ggui-spacing-4)">
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
              5-Day Forecast
            </Text>
            <Row justify="between" align="center" wrap gap="var(--ggui-spacing-4)">
              {props.forecast?.slice(0, 5).map((item, index) => (
                <Box
                  key={index}
                  padding="var(--ggui-spacing-3)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-lg)"
                  style={{ minWidth: '80px', flex: 1 }}
                >
                  <Stack align="center" gap="var(--ggui-spacing-2)">
                    <Text variant="caption" weight="bold" color="var(--ggui-color-onSurfaceVariant)">
                      {item.day ? item.day.substring(0, 3).toUpperCase() : `D${index + 1}`}
                    </Text>
                    <WeatherIcon condition={item.icon || 'Cloudy'} size={32} color="var(--ggui-color-primary-500)" />
                    <Stack gap="0" align="center">
                      <Text variant="bodySmall" weight="bold" color="var(--ggui-color-onSurface)">
                        {item.high}°
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {item.low}°
                      </Text>
                    </Stack>
                  </Stack>
                </Box>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

