import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed
/** Validation helper for email format */
const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

/** Summary row for the review step */
function ReviewRow(props: { label: string; value: React.ReactNode }) {
  return (
    <Stack gap="var(--ggui-spacing-1)">
      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">{props.label}</Text>
      <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
        <Text variant="body">{props.value || <Text italic color="var(--ggui-color-onSurfaceVariant)">Not provided</Text>}</Text>
      </Box>
    </Stack>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<ActionSubmitPayload>({
    name: '',
    email: '',
    satisfaction: 0,
    features: [],
    comments: '',
  });

  const isStepValid = useMemo(() => {
    switch (step) {
      case 1: return formData.name.trim().length > 0 && isValidEmail(formData.email);
      case 2: return formData.satisfaction > 0;
      case 3: return true;
      case 4: return formData.comments.length <= 500;
      default: return true;
    }
  }, [step, formData]);

  const handleNext = useCallback(() => {
    if (isStepValid && step < 5) setStep(s => s + 1);
  }, [isStepValid, step]);

  const handleBack = useCallback(() => {
    if (step > 1) setStep(s => s - 1);
  }, [step]);

  const handleSubmit = useCallback(() => {
    submit(formData);
  }, [formData, submit]);

  const satisfactionOptions = useMemo(() => {
    return props.satisfactionLabels.map((label, index) => ({
      value: String(index + 1),
      label: label,
    }));
  }, [props.satisfactionLabels]);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-10)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Progress Header */}
        <Stack gap="var(--ggui-spacing-3)">
          <Row justify="between" align="end">
            <Heading level={2}>
              {step === 5 ? 'Review Your Responses' : 'Survey Form'}
            </Heading>
            <Badge variant="default" size="lg">
              {step === 5 ? 'Final Step' : `Step ${step} of 4`}
            </Badge>
          </Row>
          <Progress value={Math.min(step, 4)} max={4} size="md" />
        </Stack>

        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="xl">
          <Stack gap="var(--ggui-spacing-6)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Contact Information</Heading>
                <Input
                  label="Full Name"
                  required
                  placeholder="Enter your name"
                  value={formData.name}
                  onChange={(val) => setFormData(prev => ({ ...prev, name: val }))}
                  error={formData.name === '' ? undefined : (formData.name.trim() === '' ? 'Name is required' : undefined)}
                />
                <Input
                  label="Email Address"
                  type="email"
                  required
                  placeholder="you@example.com"
                  value={formData.email}
                  onChange={(val) => setFormData(prev => ({ ...prev, email: val }))}
                  error={formData.email !== '' && !isValidEmail(formData.email) ? 'Please enter a valid email' : undefined}
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Overall Satisfaction</Heading>
                <RadioGroup
                  label="How satisfied are you with our service?"
                  value={String(formData.satisfaction)}
                  onChange={(val) => setFormData(prev => ({ ...prev, satisfaction: Number(val) }))}
                  options={satisfactionOptions}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Feature Interests</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)" variant="bodySmall">Select all features you are interested in:</Text>
                <Stack gap="var(--ggui-spacing-2)">
                  {props.featureOptions.map(option => (
                    <Checkbox
                      key={option}
                      label={option}
                      checked={formData.features.includes(option)}
                      onChange={(checked) => {
                        setFormData(prev => ({
                          ...prev,
                          features: checked
                            ? [...prev.features, option]
                            : prev.features.filter(f => f !== option)
                        }));
                      }}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Additional Comments</Heading>
                <TextArea
                  label="Any other feedback?"
                  placeholder="Tell us what you think..."
                  value={formData.comments}
                  onChange={(val) => setFormData(prev => ({ ...prev, comments: val }))}
                  maxLength={500}
                  showCount
                  rows={5}
                />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap="var(--ggui-spacing-5)">
                <Heading level={4}>Summary of Answers</Heading>
                <ReviewRow label="Name" value={formData.name} />
                <ReviewRow label="Email" value={formData.email} />
                <ReviewRow label="Satisfaction" value={props.satisfactionLabels[formData.satisfaction - 1]} />
                <ReviewRow label="Features" value={formData.features.length > 0 ? formData.features.join(', ') : 'None selected'} />
                <ReviewRow label="Comments" value={formData.comments} />
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-4)" />

            <Row justify="between">
              <Button
                as={Clickable}
                variant="ghost"
                disabled={step === 1}
                onClick={handleBack}
                leftIcon={<Icon name="arrow-left" size={16} />}
              >
                Back
              </Button>

              {step < 5 ? (
                <Button
                  as={Clickable}
                  variant="primary"
                  disabled={!isStepValid}
                  onClick={handleNext}
                  rightIcon={<Icon name="arrow-right" size={16} />}
                >
                  Next
                </Button>
              ) : (
                <Button
                  as={Clickable}
                  variant="primary"
                  onClick={handleSubmit}
                  rightIcon={<Icon name="check" size={16} />}
                >
                  Submit Survey
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );


}

