import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





const CATEGORY_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-error-100)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-100)',
  'lanthanide': 'var(--ggui-color-info-100)',
  'actinide': 'var(--ggui-color-primary-100)',
  'transition-metal': 'var(--ggui-color-surfaceVariant)',
  'post-transition-metal': 'var(--ggui-color-success-100)',
  'metalloid': 'var(--ggui-color-primary-200)',
  'polyatomic-nonmetal': 'var(--ggui-color-success-200)',
  'diatomic-nonmetal': 'var(--ggui-color-success-300)',
  'noble-gas': 'var(--ggui-color-info-200)',
  'nonmetal': 'var(--ggui-color-success-400)',
  'halogen': 'var(--ggui-color-warning-200)',
};

function getCategoryColor(category?: string) {
  if (!category) return 'var(--ggui-color-surfaceVariant)';
  const key = category.toLowerCase().replace(/\s+/g, '-');
  return CATEGORY_COLORS[key] || 'var(--ggui-color-outlineVariant)';
}

function ElementDetailItem(props: { label: string; value?: string | number }) {
  return (
    <Stack gap="var(--ggui-spacing-1)">
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" weight="medium">
        {props.label}
      </Text>
      <Text variant="bodyLarge" weight="semibold">
        {props.value ?? 'N/A'}
      </Text>
    </Stack>
  );
}

export default function Component(props: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    const term = searchTerm.toLowerCase().trim();
    const elements = props.elements || [];
    if (!term) return elements;
    return elements.filter(e =>
      e.name?.toLowerCase().includes(term) || e.symbol?.toLowerCase().includes(term)
    );
  }, [props.elements, searchTerm]);

  const selectedElement = useMemo(() => {
    return (props.elements || []).find(e => e.atomicNumber === selectedAtomicNumber);
  }, [props.elements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const cats = new Set<string>();
    (props.elements || []).forEach(e => {
      if (e.category) cats.add(e.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <SearchField
            value={searchTerm}
            onChange={setSearchTerm}
            placeholder="Search by name or symbol..."
            size="lg"
            aria-label="Search elements"
          />
        </Stack>

        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4)' }}>
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, 1fr)',
              gap: 'var(--ggui-spacing-1)',
              minWidth: '1100px',
            }}
          >
            {filteredElements.map((element) => (
              <Box
                key={element.atomicNumber}
                as={Clickable}
                onClick={() => setSelectedAtomicNumber(element.atomicNumber ?? null)}
                aria-label={`${element.name}, Atomic number ${element.atomicNumber}`}
                style={{
                  gridColumn: element.col,
                  gridRow: element.row,
                  aspectRatio: '1 / 1',
                  background: getCategoryColor(element.category),
                  border: `1px solid ${selectedAtomicNumber === element.atomicNumber ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'}`,
                  borderRadius: 'var(--ggui-shape-radius-sm)',
                  position: 'relative',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  transition: 'all 0.2s',
                  boxShadow: selectedAtomicNumber === element.atomicNumber ? 'var(--ggui-shape-shadow-md)' : 'none',
                  transform: selectedAtomicNumber === element.atomicNumber ? 'scale(1.05)' : 'none',
                  zIndex: selectedAtomicNumber === element.atomicNumber ? 10 : 1,
                }}
                hoverStyle={{ opacity: 0.8, transform: 'scale(1.02)' }}
              >
                <Text
                  style={{ position: 'absolute', top: '2px', left: '4px' }}
                  variant="caption"
                  size="xs"
                  weight="bold"
                >
                  {element.atomicNumber}
                </Text>
                <Text variant="bodyLarge" weight="bold" size="lg">
                  {element.symbol}
                </Text>
                <Text variant="caption" size="xs" truncate style={{ maxWidth: '90%' }}>
                  {element.name}
                </Text>
              </Box>
            ))}
          </div>
        </Box>

        <Row gap="var(--ggui-spacing-6)" align="start" wrap>
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: '1 1 300px' }}>
            <Heading level={2}>Legend</Heading>
            <Row wrap gap="var(--ggui-spacing-3)">
              {categories.map(cat => (
                <Row key={cat} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    width="14px"
                    height="14px"
                    borderRadius="var(--ggui-shape-radius-sm)"
                    background={getCategoryColor(cat)}
                    style={{ border: '1px solid var(--ggui-color-outlineVariant)' }}
                  />
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{cat}</Text>
                </Row>
              ))}
            </Row>
          </Stack>

          {selectedElement && (
            <Card padding="var(--ggui-spacing-6)" shadow="md" style={{ flex: '1 1 400px', animation: 'ggui-fadeIn 200ms ease-out' }}>
              <Stack gap="var(--ggui-spacing-4)">
                <Row justify="between" align="center">
                  <Stack gap="0">
                    <Heading level={2}>{selectedElement.name}</Heading>
                    <Text variant="bodyLarge" color="var(--ggui-color-primary-600)" weight="semibold">
                      {selectedElement.category}
                    </Text>
                  </Stack>
                  <Box
                    padding="var(--ggui-spacing-4)"
                    background={getCategoryColor(selectedElement.category)}
                    borderRadius="var(--ggui-shape-radius-lg)"
                    style={{ minWidth: '80px', textAlign: 'center', border: '2px solid var(--ggui-color-outline)' }}
                  >
                    <Text variant="bodyLarge" size="3xl" weight="bold">{selectedElement.symbol}</Text>
                  </Box>
                </Row>

                <Divider margin="var(--ggui-spacing-2)" />

                <Row gap="var(--ggui-spacing-8)" wrap>
                  <ElementDetailItem label="Atomic Number" value={selectedElement.atomicNumber} />
                  <ElementDetailItem label="Atomic Weight" value={selectedElement.atomicWeight} />
                </Row>
              </Stack>
            </Card>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

