// Helper for rendering rating stars
function RatingStars(props: { rating: number }) {
  return (
    <Row gap="var(--ggui-spacing-1)" align="center">
      {[1, 2, 3, 4, 5].map((star) => (
        <Icon
          key={star}
          name="star"
          size={18}
          color={star <= props.rating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
        />
      ))}
    </Row>
  );
