// Helper for rendering the stock badge
function StockBadge(props: { stock: number }) {
  if (props.stock === 0) {
    return <Badge variant="error">Out of Stock</Badge>;
  }
  if (props.stock <= 10) {
    return <Badge variant="warning">Low Stock ({props.stock} left)</Badge>;
  }
  return <Badge variant="success">In Stock</Badge>;
}

