// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




/** Formatting helper for timestamps */
const formatTime = (timestamp?: string) => {
  if (!timestamp) return '';
  try {
    return new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch (e) {
    return '';
  }
};


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [inputText, setInputText] = useState('');
  const [localMessages, setLocalMessages] = useState<StreamMessage[]>([]);
  const [typingMap, setTypingMap] = useState<Record<string, boolean>>({});
  const scrollRef = useRef<HTMLDivElement>(null);

  // Sync stream messages to local list
  useEffect(() => {
    if (message.latest) {
      setLocalMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Update typing indicator state
  useEffect(() => {
    if (typing.latest && typing.latest.sender) {
      setTypingMap((prev) => ({
        ...prev,
        [typing.latest!.sender!]: !!typing.latest!.active,
      }));
    }
  }, [typing.latest]);

  // Combine initial messages from props with new ones from stream
  const allMessages = useMemo(() => {
    return [...(props.messages || []), ...localMessages];
  }, [props.messages, localMessages]);

  // Auto-scroll to bottom on new messages
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [allMessages]);

  const handleSend = useCallback(() => {
    if (!inputText.trim()) return;
    const payload: ActionSendMessagePayload = {
      text: inputText,
      timestamp: new Date().toISOString(),
    };
    sendMessage(payload);
    // Optimistically add to list or let the stream handle it? 
    // Usually agent reflects back via stream, but let's assume fire-and-forget for this task.
    // We'll add it locally to show it immediately since the prompt implies sendMessage returns nothing.
    setLocalMessages(prev => [...prev, { sender: props.currentUser, text: inputText, timestamp: payload.timestamp }]);
    setInputText('');
  }, [inputText, props.currentUser, sendMessage]);

  const typingUsers = Object.entries(typingMap)
    .filter(([name, active]) => active && name !== props.currentUser)
    .map(([name]) => name);

  return (
    <Container maxWidth="lg" padding={0}>
      <Card padding={0} shadow="md" radius="lg" border style={{ height: '90vh', display: 'flex', flexDirection: 'column' }}>
        {/* Header Area */}
        <Box padding="var(--ggui-spacing-4)" borderBottom="1px solid var(--ggui-color-outlineVariant)" background="var(--ggui-color-surface)">
          <Row align="center" justify="between">
            <Stack gap="var(--ggui-spacing-1)">
              <Row gap="var(--ggui-spacing-3)" align="center">
                <Heading level={4}>{props.title}</Heading>
                <Badge variant="primary" pill>{props.participantCount} online</Badge>
              </Row>
              {typingUsers.length > 0 && (
                <Text variant="caption" color="var(--ggui-color-primary-600)" style={{ animation: 'ggui-pulse 2s infinite' }}>
                  {typingUsers.join(', ')} {typingUsers.length === 1 ? 'is' : 'are'} typing...
                </Text>
              )}
            </Stack>
          </Row>
        </Box>

        {/* Messages List Area */}
        <Box
          ref={scrollRef}
          style={{ flex: 1, overflowY: 'auto' }}
          padding="var(--ggui-spacing-4)"
          background="var(--ggui-color-surface)"
        >
          <Stack gap="var(--ggui-spacing-3)">
            {allMessages.map((msg, index) => {
              const isMe = msg.sender === props.currentUser;
              const prevMsg = allMessages[index - 1];
              const showSender = !isMe && (!prevMsg || prevMsg.sender !== msg.sender);
              const isGrouped = prevMsg && prevMsg.sender === msg.sender;

              return (
                <Box key={index} style={{ alignSelf: isMe ? 'flex-end' : 'flex-start', maxWidth: '80%' }}>
                  {showSender && (
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" style={{ marginLeft: 'var(--ggui-spacing-2)', marginBottom: 'var(--ggui-spacing-1)' }}>
                      {msg.sender}
                    </Text>
                  )}
                  <Card
                    padding="var(--ggui-spacing-2) var(--ggui-spacing-3)"
                    radius="lg"
                    shadow="none"
                    border={false}
                    background={isMe ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                    style={{ minWidth: 0 }}
                  >
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text color={isMe ? 'white' : 'var(--ggui-color-onSurface)'}>
                        {msg.text}
                      </Text>
                      <Row justify="end">
                        <Text variant="caption" color={isMe ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant)'}>
                          {formatTime(msg.timestamp)}
                        </Text>
                      </Row>
                    </Stack>
                  </Card>
                </Box>
              );
            })}
            {allMessages.length === 0 && (
              <Box paddingY="var(--ggui-spacing-12)" align="center">
                <Text color="var(--ggui-color-onSurfaceVariant)">No messages yet. Start the conversation!</Text>
              </Box>
            )}
          </Stack>
        </Box>

        {/* Input Area */}
        <Box padding="var(--ggui-spacing-4)" borderTop="1px solid var(--ggui-color-outlineVariant)" background="var(--ggui-color-surface)">
          <Row gap="var(--ggui-spacing-3)" align="end">
            <Box style={{ flex: 1 }}>
              <TextArea
                label="Message"
                placeholder="Type your message..."
                value={inputText}
                onChange={setInputText}
                rows={1}
                autoResize
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button
              as={Clickable}
              onClick={handleSend}
              disabled={!inputText.trim()}
              variant="primary"
              size="md"
              rightIcon={<Icon name="send" size={18} />}
            >
              Send
            </Button>
          </Row>
        </Box>
      </Card>
    </Container>
    );
}

