export default function Component(props: Props) {
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate');
  const marketStatus = useStream<StreamMarketStatus>('marketStatus');

  // Local state to manage merged stock data
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastRefreshed, setLastRefreshed] = useState(new Date());

  // Merge price updates into local state
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks(current => (current || []).map(s => (s.symbol === update.symbol ? { ...s, ...update } : s)));
      setLastRefreshed(new Date());
    }
  }, [priceUpdate.latest]);

  // Update "Last Updated" clock in real-time
  const [currentTime, setCurrentTime] = useState(new Date());
  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const marketLabel = marketStatus.latest?.status || 'Market Closed';
  const marketVariant = marketStatus.latest?.status === 'open' ? 'success' : 'warning';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
