              Real-time market insights and live price updates.
            </Text>          
          </Stack>
          <Stack align="end" gap="0">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">LAST UPDATED</Text>
            <Text variant="body" weight="medium">{formatTime(currentTime)}</Text>
          </Stack>
        </Row>

        <Divider margin="0" />

        <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={24}>
          {stocks?.map((stock) => (
            <StockCard key={stock.symbol} stock={stock} />
          ))}
        </CardGrid>
      </Stack>
    </Container>
  );
}

