import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Place helper components here if needed

const validateEmail = (email: string) => {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
};

function StepIndicator(props: { currentStep: number }) {
  const percent = (props.currentStep / 3) * 100;
  return (
    <Stack gap="var(--ggui-spacing-4)">
      <Row justify="between" align="center">
        <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
          <Badge variant={props.currentStep >= 1 ? 'primary' : 'default'} pill>1</Badge>
          <Text variant="label" color={props.currentStep >= 1 ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-onSurfaceVariant)'}>Profile</Text>
        </Stack>
        <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
          <Badge variant={props.currentStep >= 2 ? 'primary' : 'default'} pill>2</Badge>
          <Text variant="label" color={props.currentStep >= 2 ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-onSurfaceVariant)'}>Preferences</Text>
        </Stack>
        <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
          <Badge variant={props.currentStep >= 3 ? 'primary' : 'default'} pill>3</Badge>
          <Text variant="label" color={props.currentStep >= 3 ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-onSurfaceVariant)'}>Confirm</Text>
        </Stack>
      </Row>
      <Progress value={percent} size="sm" />
    </Stack>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || '',
    role: props.initialProfile?.role || '',
    emailNotifications: props.initialProfile?.emailNotifications ?? true,
    theme: props.initialProfile?.theme || 'light',
  });

  const isStep1Valid = useMemo(() => {
    return (
      formData.name.trim().length > 0 &&
      validateEmail(formData.email) &&
      formData.avatar.length > 0
    );
  }, [formData.name, formData.email, formData.avatar]);

  const isStep2Valid = useMemo(() => {
    return formData.role.length > 0;
  }, [formData.role]);

  const handleNext = useCallback(() => {
    setStep((s) => Math.min(s + 1, 3));
  }, []);

  const handleBack = useCallback(() => {
    setStep((s) => Math.max(s - 1, 1));
  }, []);

  const handleSubmit = useCallback(() => {
    complete({
      name: formData.name,
      email: formData.email,
      avatar: formData.avatar,
      role: formData.role,
      emailNotifications: formData.emailNotifications,
      theme: formData.theme,
    });
  }, [complete, formData]);

  const [opacity, setOpacity] = useState(1);
  useEffect(() => {
    setOpacity(0);
    const timer = setTimeout(() => setOpacity(1), 100);
    return () => clearTimeout(timer);
  }, [step]);

  const roleOptions = useMemo(() => {
    return (props.roleOptions || []).map((role) => ({ value: role, label: role }));
  }, [props.roleOptions]);
  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-10)">
      <Stack gap="var(--ggui-spacing-8)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>Account Setup</Heading>
          <Text color="var(--ggui-color-onSurfaceVariant)">
            Follow the steps to complete your profile
          </Text>
        </Stack>

        <StepIndicator currentStep={step} />

        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="xl">
          <Box style={{ opacity, transition: 'opacity 0.2s ease-in-out' }}>
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-6)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Full Name"
                  placeholder="Enter your name"
                  value={formData.name}
                  onChange={(val) => setFormData((prev) => ({ ...prev, name: val }))}
                  required
                />
                <Input
                  label="Email Address"
                  type="email"
                  placeholder="you@example.com"
                  value={formData.email}
                  onChange={(val) => setFormData((prev) => ({ ...prev, email: val }))}
                  required
                  error={formData.email && !validateEmail(formData.email) ? 'Please enter a valid email' : undefined}
                />
                <Stack gap="var(--ggui-spacing-3)">
                  <Text variant="label">Select an Avatar</Text>
                  <Row gap="var(--ggui-spacing-4)" wrap>

                    {(props.avatarOptions || []).map((emoji) => (
                      <Box
                        key={emoji}
                        as={Clickable}
                        onClick={() => setFormData((prev) => ({ ...prev, avatar: emoji }))}
                        padding="var(--ggui-spacing-2)"
                        style={{
                          backgroundColor: formData.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'transparent',
                          borderRadius: 'var(--ggui-shape-radius-lg)',
                          border: `2px solid ${formData.avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'}`,
                          transition: 'all 0.2s ease',
                        }}
                      >
                        <Text size="3xl">{emoji}</Text>
                      </Box>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-6)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="What is your role?"
                  options={roleOptions}
                  placeholder="Select a role"
                  value={formData.role}
                  onChange={(val) => setFormData((prev) => ({ ...prev, role: val }))}
                  required
                />
                <Toggle
                  label="Receive email notifications"
                  checked={formData.emailNotifications}
                  onChange={(val) => setFormData((prev) => ({ ...prev, emailNotifications: val }))}
                />
                <Toggle
                  label="Dark Theme"
                  checked={formData.theme === 'dark'}
                  onChange={(val) => setFormData((prev) => ({ ...prev, theme: val ? 'dark' : 'light' }))}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-6)">
                <Heading level={4}>Review & Confirm</Heading>
                <Box
                  padding="var(--ggui-spacing-4)"
                  style={{
                    backgroundColor: 'var(--ggui-color-surfaceVariant)',
                    borderRadius: 'var(--ggui-shape-radius-lg)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-4)">
                    <Row align="center" gap="var(--ggui-spacing-4)">
                      <Box
                        padding="var(--ggui-spacing-2)"
                        style={{
                          backgroundColor: 'var(--ggui-color-surface)',
                          borderRadius: 'var(--ggui-shape-radius-full)',
                          fontSize: '40px',
                          lineHeight: '1',
                        }}
                      >
                        {formData.avatar}
                      </Box>
                      <Stack gap="0">
                        <Heading level={5}>{formData.name}</Heading>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{formData.email}</Text>
                      </Stack>
                    </Row>
                    <Divider />
                    <Row justify="between">
                      <Text variant="label">Role</Text>
                      <Badge variant="primary">{formData.role}</Badge>
                    </Row>
                    <Row justify="between">
                      <Text variant="label">Notifications</Text>
                      <Text variant="bodySmall">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                    </Row>
                    <Row justify="between">
                      <Text variant="label">Theme</Text>
                      <Text variant="bodySmall" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
                    </Row>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>
        </Card>


        <Row justify="between" align="center">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={step === 1}
            leftIcon={<Icon name="chevron-left" size={18} />}
          >
            Back
          </Button>

          {step < 3 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={(step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid)}
              rightIcon={<Icon name="chevron-right" size={18} />}
            >
              Next Step
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
              leftIcon={<Icon name="check" size={18} />}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
